  1	import { type FC, useEffect, useState } from 'react';
  2	import {
  3	  Controller,
  4	  type FieldPath,
  5	  type FieldValues,
  6	  useFormContext,
  7	  useWatch,
  8	} from 'react-hook-form';
  9	
 10	import FormGroupWithErrorText from '@components/common/FormGroupWithErrorText';
 11	import { HelpIconPopover } from '@components/common/HelpIconPopover/HelpIconPopover';
 12	import ProjectSelect from '@components/common/ProjectSelect/ProjectSelect';
 13	import { MenuToggleStatus, Stack, StackItem } from '@patternfly/react-core';
 14	import { useDefaultProject } from '@utils/hooks/useDefaultProject';
 15	import useWatchProjectNames from '@utils/hooks/useWatchProjectNames';
 16	import { useForkliftTranslation } from '@utils/i18n';
 17	import { isSystemNamespace } from '@utils/namespaces';
 18	
 19	import { NetworkMapFieldId, networkMapFieldLabels } from '../../constants';
 20	import type { CreateNetworkMapFormData } from '../types';
 21	
 22	const ProjectSelectField: FC = () => {
 23	  const { t } = useForkliftTranslation();
 24	  const {
 25	    control,
 26	    formState: { errors, isSubmitting },
 27	    setValue,
 28	  } = useFormContext<CreateNetworkMapFormData>();
 29	  const [targetProvider, sourceProvider] = useWatch({
 30	    control,
 31	    name: [NetworkMapFieldId.TargetProvider, NetworkMapFieldId.SourceProvider],
 32	  });
 33	  const [projectNames] = useWatchProjectNames();
 34	
 35	  const defaultProject = useDefaultProject(projectNames);
 36	  const [showDefaultProjects, setShowDefaultProjects] = useState<boolean>(false);
 37	
 38	  // Automatically set the default project once it's resolved
 39	  useEffect(() => {
 40	    if (defaultProject) {
 41	      setValue(NetworkMapFieldId.Project, defaultProject);
 42	      setShowDefaultProjects((prev) => prev || isSystemNamespace(defaultProject));
 43	    }
 44	  }, [defaultProject, setValue]);
 45	
 46	  return (
 47	    <FormGroupWithErrorText
 48	      isRequired
 49	      fieldId={NetworkMapFieldId.Project}
 50	      label={networkMapFieldLabels[NetworkMapFieldId.Project]}
 51	      labelIcon={
 52	        <HelpIconPopover>
 53	          <Stack hasGutter>
 54	            <StackItem>{t('The project that your network map will be created in.')}</StackItem>
 55	            <StackItem>
 56	              {t('Projects, also known as namespaces, separate resources within clusters.')}
 57	            </StackItem>
 58	          </Stack>
 59	        </HelpIconPopover>
 60	      }
 61	    >
 62	      <Controller
 63	        name={NetworkMapFieldId.Project}
 64	        control={control}
 65	        render={({ field }) => (
 66	          <div ref={field.ref}>
 67	            <ProjectSelect
 68	              showDefaultProjects={showDefaultProjects}
 69	              setShowDefaultProjects={setShowDefaultProjects}
 70	              isDisabled={isSubmitting}
 71	              placeholder={t('Select project')}
 72	              id={NetworkMapFieldId.Project}
 73	              testId="network-map-project-select"
 74	              projectNames={projectNames}
 75	              value={field.value}
 76	              onChange={(value) => {
 77	                field.onChange(value);
 78	
 79	                if (sourceProvider) {
 80	                  setValue<FieldPath<FieldValues>>(NetworkMapFieldId.SourceProvider, '', {
 81	                    shouldValidate: true,
 82	                  });
 83	                }
 84	                if (targetProvider) {
 85	                  setValue<FieldPath<FieldValues>>(NetworkMapFieldId.TargetProvider, '', {
 86	                    shouldValidate: true,
 87	                  });
 88	                }
 89	              }}
 90	              toggleProps={{
 91	                status: errors[NetworkMapFieldId.Project] && MenuToggleStatus.danger,
 92	              }}
 93	            />
 94	          </div>
 95	        )}
 96	        rules={{ required: t('Project is required.') }}
 97	      />
 98	    </FormGroupWithErrorText>
 99	  );
100	};
101	
102	export default ProjectSelectField;

